#include <stdio.h>
#include <stdbool.h>

bool searchMatrix(int rows, int cols, int target, int matrix[1000][1000]) {
    int left = 0, right = rows * cols - 1;
    while (left <= right) {
        int mid = left + (right - left) / 2;
        int val = matrix[mid / cols][mid % cols];
        if (val == target) return true;
        if (val < target) left = mid + 1; else right = mid - 1;
    }
    return false;
}

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N, M, target;
        scanf("%d %d", &N, &M);
        int matrix[1000][1000];
        for (int i = 0; i < N; ++i) {
            for (int j = 0; j < M; ++j) {
                scanf("%d", &matrix[i][j]);
            }
        }
        scanf("%d", &target);
        printf(searchMatrix(N, M, target, matrix) ? "YES\n" : "NO\n");
    }
    return 0;
}

