import sys

def search_matrix(mat, rows, cols, target):
    left, right = 0, rows * cols - 1
    while left <= right:
        mid = (left + right) // 2
        val = mat[mid // cols][mid % cols]
        if val == target:
            return True
        if val < target:
            left = mid + 1
        else:
            right = mid - 1
    return False

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        N = int(next(it)); M = int(next(it))
        matrix = [[int(next(it)) for _ in range(M)] for __ in range(N)]
        target = int(next(it))
        out.append('YES' if search_matrix(matrix, N, M, target) else 'NO')
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    main()

